INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$14754755-bd97-4b42-b285-76a4be57e0c8$tag$, $tag$2026012800147$tag$, $tag$Su Ortiz (5584996968243)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página de Pós graduação e quero mais informações.","time":"28/01/2026 15:47:22"},{"role":"client","text":"🌟 Boa tarde Su Ortiz! Que alegria ter você aqui com a gente! 🙌","time":"28/01/2026 15:47:23"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"28/01/2026 15:47:27"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"28/01/2026 15:47:31"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"28/01/2026 15:47:35"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"28/01/2026 15:47:42"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"28/01/2026 15:47:48"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"28/01/2026 15:47:49"},{"role":"client","text":"Sim, concordo","time":"28/01/2026 15:48:27"},{"role":"client","text":"✅ Obrigado, Su Ortiz! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"28/01/2026 15:48:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"28/01/2026 15:48:33"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"28/01/2026 15:48:48"},{"role":"client","text":"Olá! Su Ortiz!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"28/01/2026 15:48:49"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"28/01/2026 15:48:53"},{"role":"client","text":"Saber sobre os cursos","time":"28/01/2026 15:49:07"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"28/01/2026 15:49:11"},{"role":"client","text":"Pós-Graduação","time":"28/01/2026 15:49:21"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"28/01/2026 15:49:25"},{"role":"client","text":"Educação Cristã Clássica","time":"28/01/2026 15:49:44"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"28/01/2026 15:49:45"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"28/01/2026 15:49:50"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"28/01/2026 15:50:02"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"28/01/2026 15:50:03"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"28/01/2026 16:00:52"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"28/01/2026 16:04:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"28/01/2026 16:04:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"28/01/2026 16:04:38","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"29/01/2026 10:44:45","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/697b9b57f39d576bc80ef479)","time":"29/01/2026 14:39:36"},{"role":"client","text":"Tem a grade curricular??","time":"29/01/2026 14:39:59"},{"role":"agent","text":"*Karina Pimentel:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"29/01/2026 14:58:09","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* PÓS GRADUAÇÃO: \nPós: Cada disciplina tem 40 horas de duração ao longo de 5 semanas, o que significa que são aproximadamente 8 horas de dedicação semanal.\n###Serão recomendados leituras e\nexercícios para cada semana, com vistas a produzir diálogos mais\nconsistentes e profundos. Os conteúdos das aulas serão disponibilizados\natravés de videoaulas gravadas (assíncronas).\nAs atividades propostas, individuais e em grupo, serão conduzidas com\n