INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2a2ee835-225a-45a0-a332-db7c55782222$tag$, $tag$2026012900034$tag$, $tag$MIRIAN E ADRIANO. (5573988949307)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia,paz do Senhor Jesus","time":"29/01/2026 08:35:09"},{"role":"client","text":"🌟 Bom dia MIRIAN E ADRIANO.! Que alegria ter você aqui com a gente! 🙌","time":"29/01/2026 08:35:10"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"29/01/2026 08:35:14"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"29/01/2026 08:35:17"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"29/01/2026 08:35:21"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"29/01/2026 08:35:27"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 08:35:33"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 08:35:34"},{"role":"client","text":"Sim, concordo","time":"29/01/2026 08:39:18"},{"role":"client","text":"✅ Obrigado, MIRIAN E ADRIANO.! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"29/01/2026 08:39:18"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 08:39:22"},{"role":"client","text":"Sistema de ensino \n Cidade Viva Education","time":"29/01/2026 08:39:47"},{"role":"client","text":"👋 Olá! Seja bem-vindo(a) ao *Cidade Viva Education*. Estou aqui para te ajudar! 😊","time":"29/01/2026 08:39:48"},{"role":"client","text":"Por favor, selecione no menu abaixo a melhor opção que se adequa à sua solicitação:","time":"29/01/2026 08:39:52"},{"role":"client","text":"Voltar ao menu anterior","time":"29/01/2026 08:40:05"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 08:40:06"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"29/01/2026 08:40:22"},{"role":"client","text":"Olá! MIRIAN E ADRIANO.!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"29/01/2026 08:40:23"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"29/01/2026 08:40:27"},{"role":"client","text":"Saber sobre os cursos","time":"29/01/2026 08:40:40"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"29/01/2026 08:40:44"},{"role":"client","text":"Graduação","time":"29/01/2026 08:41:01"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"29/01/2026 08:41:05"},{"role":"client","text":"Teologia (EAD)","time":"29/01/2026 08:41:18"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"29/01/2026 08:41:19"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"29/01/2026 08:41:23"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"29/01/2026 08:41:48"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"29/01/2026 08:41:48"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 08:46:56"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"29/01/2026 08:47:19","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia Karina","time":"29/01/2026 08:47:24"},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"29/01/2026 08:47:32","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Brigada tenha um ótimo dia","time":"29/01/2026 08:48:56"},{"role":"agent","text":"*Karina Pimentel:* \n   Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"29/01/2026 17:53:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nMIRIAN E ADRIANO., esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 17:53:17"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"29/01/2026 17:53:18"},{"role":"client","text":"MIRIAN E ADRIANO., Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"29/01/2026 18:08:19"}]$tag$, $tag$2026-01-29 08:35:09+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_na