INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5d215e40-8900-4134-ab05-fb239faa53ca$tag$, $tag$2026012900061$tag$, $tag$. (5599991510747)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"29/01/2026 10:43:41"},{"role":"client","text":"🌟 Bom dia .! Que alegria ter você aqui com a gente! 🙌","time":"29/01/2026 10:43:42"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"29/01/2026 10:43:46"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"29/01/2026 10:43:51"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"29/01/2026 10:43:55"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"29/01/2026 10:44:01"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 10:44:07"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 10:44:08"},{"role":"client","text":"Não concordo","time":"29/01/2026 10:44:58"},{"role":"client","text":"🔒 Entendemos e respeitamos sua decisão, ..\n\nDe acordo com a LGPD, só podemos continuar com o atendimento mediante o seu consentimento para uso dos dados informados (como nome e CPF), exclusivamente para fins de atendimento.\n\nCaso mude de ideia e deseje continuar, é só digitar \"*Concordo*\" a qualquer momento.  \nEstamos à disposição. 😊\n","time":"29/01/2026 10:44:59"},{"role":"client","text":"Concordo","time":"29/01/2026 10:46:35"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 10:46:39"},{"role":"client","text":"Sistema de ensino \n Cidade Viva Education","time":"29/01/2026 10:47:17"},{"role":"client","text":"👋 Olá! Seja bem-vindo(a) ao *Cidade Viva Education*. Estou aqui para te ajudar! 😊","time":"29/01/2026 10:47:18"},{"role":"client","text":"Por favor, selecione no menu abaixo a melhor opção que se adequa à sua solicitação:","time":"29/01/2026 10:47:21"},{"role":"client","text":"Currículos disponíveis \n Quero conhecer os currículos disponíveis","time":"29/01/2026 10:47:47"},{"role":"client","text":"Temos 3 frentes principais. Veja e selecione abaixo qual delas você deseja conhecer:","time":"29/01/2026 10:47:51"},{"role":"client","text":"Voltar ao menu anterior","time":"29/01/2026 10:49:28"},{"role":"client","text":"Por favor, selecione no menu abaixo a melhor opção que se adequa à sua solicitação:","time":"29/01/2026 10:49:32"},{"role":"client","text":"Voltar ao menu anterior","time":"29/01/2026 10:49:51"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 10:49:51"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"29/01/2026 10:50:02"},{"role":"client","text":"Olá! .!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"29/01/2026 10:50:02"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"29/01/2026 10:50:06"},{"role":"client","text":"Saber sobre os cursos","time":"29/01/2026 10:50:22"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"29/01/2026 10:50:26"},{"role":"client","text":"Pós-Graduação","time":"29/01/2026 10:50:40"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"29/01/2026 10:50:44"},{"role":"client","text":"Novo Testamento","time":"29/01/2026 10:51:01"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"29/01/2026 10:51:01"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"29/01/2026 10:51:05"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"29/01/2026 10:51:31"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"29/01/2026 10:51:32"},{"role":"client","text":"Ok","time":"29/01/2026 10:52:06"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 10:59:28"},{"role":"client","text":"Qual o valor da pós?","time":"29/01/2026 11:00:35"},{"role":"client","text":"Em Novo Testamento","time":"29/01/2026 11:00:52"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"29/01/2026 11:04:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"29/01/2026 11:04:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊","time":"29/01/2026 11:05:14","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"29/01/2026 18:15:02","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\n., esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 18:15:03"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"29/01/2026 18:15:04"},{"role":"client","text":"., Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"29/01/2026 18:30:05"}]$tag$, $tag$2026-01-29 10:43:41+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
