INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$21df4931-6a64-4ac5-bf91-aedf77e274e2$tag$, $tag$2026012900091$tag$, $tag$Karen Wolga (1418484699728351)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Gostaria de ver o conteúdo programático e confirmar se o professe é o sayao. As aulas são gravadas ou live ?","time":"29/01/2026 12:53:32"},{"role":"client","text":"Olá aguarde só um momento que em breve alguém da nossa equipe irá te responder.","time":"29/01/2026 12:53:33"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 13:03:04"},{"role":"agent","text":"Karina Pimentel: Olá!","time":"29/01/2026 13:03:18","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"Karina Pimentel:  Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\nNossa carga horária é de 440h.\n\nDISCIPLINAS\nContamos com um total de 12 disciplinas.\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"29/01/2026 13:03:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Karina Pimentel: O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"29/01/2026 13:04:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Karina Pimentel: Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊","time":"29/01/2026 13:04:53","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"Karina Pimentel:  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"29/01/2026 18:19:02","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nKaren Wolga, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 18:19:03"},{"role":"client","text":"Obrigado por entrar em contato conosco!\n\nVolte sempre!","time":"29/01/2026 18:19:04"}]$tag$, $tag$2026-01-29 12:53:32+00$tag$, FALSE, FALSE, 7.4, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 9, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$eb8dd770-4797-454d-a9dd-08b4001a82df$tag$, $tag$2026012900093$tag$, $tag$Não identificado (5581986267591)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"29/01/2026 12:59:10"},{"role":"client","text":"🌟 Boa tarde {{name}}! Que alegria ter você aqui com a gente! 🙌","time":"29/01/2026 12:59:11"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"29/01/2026 12:59:15"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"29/01/2026 12:59:18"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"29/01/2026 12:59:22"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"29/01/2026 12:59:28"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 12:59:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 12:59:35"},{"role":"client","text":"Sim, concordo","time":"29/01/2026 12:59:47"},{"role":"client","text":"✅ Obrigado, {{name}}! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"29/01/2026 12:59:48"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 12:59:52"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"29/01/2026 13:00:07"},{"role":"client","text":"Olá! !👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"29/01/2026 13:00:07"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"29/01/2026 13:00:11"},{"role":"client","text":"Saber sobre os cursos","time":"29/01/2026 13:00:26"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"29/01/2026 13:00:30"},{"role":"client","text":"Graduação","time":"29/01/2026 13:00:49"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"29/01/2026 13:00:53"},{"role":"client","text":"Teologia (EAD)","time":"29/01/2026 13:01:07"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"29/01/2026 13:01:09"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"29/01/2026 13:01:12"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"29/01/2026 13:01:37"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"29/01/2026 13:01:38"},{"role":"client","text":"Ok","time":"29/01/2026 13:01:53"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 13:04:56"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"29/01/2026 13:05:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"29/01/2026 13:05:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"29/01/2026 13:13:26"},{"role":"client","text":"Deus abençoe","time":"29/01/2026 13:13:28"},{"role":"agent","text":"*Karina Pimentel:*      \n  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"30/01/2026 11:36:23","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Agradeço","time":"30/01/2026 15:10:23"},{"role":"client","text":"Muito caro","time":"30/01/2026 15:10:27"},{"role":"agent","text":"*Karina Pimentel:* Consigo um desconto de 20%.","time":"30/01/2026 16:15:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"30/01/2026 16:15:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tem bolsa pra quem fez o Enem","time":"30/01/2026 16:16:37"},{"role":"client","text":"?","time":"30/01/2026 16:16:39"},{"role":"agent","text":"*Karina Pimentel:* Seria o mesmo valor.","time":"30/01/2026 16:17:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Seria uma das formas de ingresso!","time":"30/01/2026 16:17:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Deus abençoe","time":"30/01/2026 16:18:21"},{"role":"client","text":"Agradeço","time":"30/01/2026 16:18:25"},{"role":"agent","text":"*Karina Pimentel:* Vamos prosseguir com a sua inscrição?","time":"30/01/2026 16:19:48","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* Posso lhe enviar o requerimento de descontos?","time":"30/01/2026 16:19:58","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Será analisado o desconto solicitado!","time":"30/01/2026 16:20:13","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Não","time":"30/01/2026 16:29:05"},{"role":"client","text":"Agradeço","time":"30/01/2026 16:29:07"},{"role":"client","text":"Vou procurar outro","time":"30/01/2026 16:29:15"},{"role":"client","text":"A Betel tá bem mais em conta","time":"30/01/2026 16:29:28"},{"role":"agent","text":"*Karina Pimentel:*  Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"30/01/2026 17:38:37","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\n, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"30/01/2026 17:38:39"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"30/01/2026 17:38:40"},{"role":"client","text":"5","time":"30/01/2026 17:41:48"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"30/01/2026 17:41:49"},{"role":"client","text":"2","time":"30/01/2026 17:42:02"},{"role":"client","text":", Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"30/01/2026 17:42:03"}]$tag$, $tag$2026-01-29 12:59:10+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 11, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
