INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$711afe6c-bc05-49fa-a406-b4d1a12078b7$tag$, $tag$2026012900106$tag$, $tag$Mattheus M. Marques (5583988993835)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"29/01/2026 13:37:12"},{"role":"client","text":"🌟 Boa tarde Mattheus M. Marques! Que alegria ter você aqui com a gente! 🙌","time":"29/01/2026 13:37:14"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"29/01/2026 13:37:18"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"29/01/2026 13:37:22"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"29/01/2026 13:37:26"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"29/01/2026 13:37:32"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 13:37:39"},{"role":"client","text":"Estou interessado no curso de teologia EaD","time":"29/01/2026 13:37:40"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 13:37:40"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 13:37:41"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 13:37:41"},{"role":"client","text":"Sim, concordo","time":"29/01/2026 13:37:58"},{"role":"client","text":"✅ Obrigado, Mattheus M. Marques! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"29/01/2026 13:37:59"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 13:38:03"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"29/01/2026 13:38:20"},{"role":"client","text":"Olá! Mattheus M. Marques!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"29/01/2026 13:38:21"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"29/01/2026 13:38:25"},{"role":"client","text":"Falar com um atendente","time":"29/01/2026 13:38:39"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"29/01/2026 13:38:40"},{"role":"client","text":"Estou interessado no curso de teologia EaD","time":"29/01/2026 13:39:03"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 13:40:24"},{"role":"client","text":"Olá","time":"29/01/2026 13:44:50"},{"role":"client","text":"Obrigado 🙏🏾","time":"29/01/2026 13:44:53"},{"role":"client","text":"…","time":"29/01/2026 13:50:21"},{"role":"client","text":"Poderia me explicar como funciona? Questão do valor da mensalidade… enfim","time":"29/01/2026 13:50:39"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"29/01/2026 15:43:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"29/01/2026 15:43:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"No caso tem até domingo para ficar no preço de 359,73?","time":"29/01/2026 16:39:33"},{"role":"agent","text":"*Karina Pimentel:* Isso.","time":"29/01/2026 16:43:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Só uma dúvida","time":"29/01/2026 16:57:42"},{"role":"client","text":"Eu pago 359,73 por exemplo, domingo que é dia 31/01. O próximo pagamento é quando?","time":"29/01/2026 16:58:02"},{"role":"agent","text":"*Karina Pimentel:* Até o dia 10/02 - 2°mensalidade!","time":"29/01/2026 17:45:50","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Se eu pagar em fevereiro, tem algum desconto","time":"29/01/2026 18:03:11"},{"role":"client","text":"ou será o preço de 432,67 fixo?","time":"29/01/2026 18:03:30"},{"role":"client","text":"Bom dia. Eu vi que tem um programa de bolsa. Como funciona e ele se aplica ao curso EaD?","time":"30/01/2026 10:47:28"},{"role":"agent","text":"*Karina Pimentel:* Somente Presencial!","time":"30/01/2026 11:27:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38","time":"30/01/2026 11:27:31","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* O senhor vai observar que o valor da semestralidade será o mesmo, vai mudar somente o valor das parcelas porque diminui a quantidade de meses!","time":"30/01/2026 11:28:26","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"A entendi","time":"30/01/2026 11:41:47"},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"30/01/2026 18:22:16","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","tex