INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$65e0ccae-b200-4d50-92d5-62e143393e88$tag$, $tag$2026012900108$tag$, $tag$Saranicolecris (5581995111654)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"29/01/2026 13:45:36"},{"role":"client","text":"🌟 Boa tarde Saranicolecris! Que alegria ter você aqui com a gente! 🙌","time":"29/01/2026 13:45:37"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"29/01/2026 13:45:41"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"29/01/2026 13:45:45"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"29/01/2026 13:45:49"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"29/01/2026 13:45:56"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 13:46:01"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 13:46:02"},{"role":"client","text":"Sim, concordo","time":"29/01/2026 13:46:24"},{"role":"client","text":"✅ Obrigado, Saranicolecris! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"29/01/2026 13:46:26"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 13:46:29"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"29/01/2026 13:46:43"},{"role":"client","text":"Olá! Saranicolecris!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"29/01/2026 13:46:45"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"29/01/2026 13:46:49"},{"role":"client","text":"Saber sobre os cursos","time":"29/01/2026 13:47:04"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"29/01/2026 13:47:08"},{"role":"client","text":"Pós-Graduação","time":"29/01/2026 13:47:19"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"29/01/2026 13:47:24"},{"role":"client","text":"Teologia Sistemática","time":"29/01/2026 13:47:56"},{"role":"client","text":"Aprofunde-se na fé cristã com uma base teológica sólida e estruturada.\n 📚 Estudos em Doutrina de Deus, Cristologia, Soteriologia, Pneumatologia e mais\n 📌 Voltado para teólogos, pastores e educadores\n 🎓 Professores mestres e doutores na área\n","time":"29/01/2026 13:47:57"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"29/01/2026 13:48:01"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"29/01/2026 13:48:23"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"29/01/2026 13:48:24"},{"role":"client","text":"Ok.","time":"29/01/2026 13:48:54"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 13:51:48"},{"role":"client","text":"Certo gostaria de saber valor e grade curricular da pós em sistemática.","time":"29/01/2026 13:52:46"},{"role":"agent","text":"*Karina Pimentel:* *Pós-Graduação em Teologia Sistemática* \n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"29/01/2026 13:53:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Teologia Sistemática está em 16 mensalidades de *R$ 359,37*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"29/01/2026 13:54:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"O conteudo a ser estudado.","time":"29/01/2026 13:56:24"},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊","time":"29/01/2026 13:58:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:*    TEOLOGIA SISTEMÁTICA - DISCIPLINAS DO CURSO:\n\nFUNDAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeoria do Método Teológico e Teologia Fundamental\nTeologia Pastoral e Missiológica \nHistória da Teologia Cristã \nPerspectivas Teológico-filosóficas na pós modernidade\n\nDESDOBRAMENTOS DA TEOLOGIA SISTEMÁTICA\nTeontologia e Trindade\nCristologia \nPneumatologia e Teologia Pentecostal\nBibliologia\nAntropologia Teológica e Hamartiologia\nSoteriologia \nEclesiologia\nEscatologia \n\nObs: Professores sujeitos a alterações. ","time":"29/01/2026 13:58:37","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Eu estou fazendo pesquisa.","time":"29/01/2026 13:58:53"},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"29/01/2026 14:22:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"29/01/2026 14:22:56","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nSaranicolecris, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"30/01/2026 15:50:46"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"30/01/2026 15:50:47"},{"role":"client","text":"Saranicolecris, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"30/01/2026 16:05:48"}]$tag$, $tag$2026-01-29 13:45:36+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
