INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5d21f149-e40a-4e0a-940a-00fa358295dc$tag$, $tag$2026012900145$tag$, $tag$Professor Assis Barroso (5585981931419)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Gestao Escolar e quero mais informações.","time":"29/01/2026 15:26:58"},{"role":"client","text":"🌟 Boa tarde Professor Assis Barroso! Que alegria ter você aqui com a gente! 🙌","time":"29/01/2026 15:26:59"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"29/01/2026 15:27:03"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"29/01/2026 15:27:07"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"29/01/2026 15:27:11"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"29/01/2026 15:27:17"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"29/01/2026 15:27:23"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"29/01/2026 15:27:24"},{"role":"client","text":"Sim, concordo","time":"29/01/2026 15:28:36"},{"role":"client","text":"✅ Obrigado, Professor Assis Barroso! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"29/01/2026 15:28:37"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"29/01/2026 15:28:41"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"29/01/2026 15:28:57"},{"role":"client","text":"Olá! Professor Assis Barroso!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"29/01/2026 15:28:58"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"29/01/2026 15:29:02"},{"role":"client","text":"Saber sobre os cursos","time":"29/01/2026 15:29:16"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"29/01/2026 15:29:21"},{"role":"client","text":"Pós-Graduação","time":"29/01/2026 15:29:33"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"29/01/2026 15:29:38"},{"role":"client","text":"Gestão Escolar","time":"29/01/2026 15:29:51"},{"role":"client","text":"Forme-se como um líder educacional com visão estratégica, conhecimento de legislação e práticas pedagógicas atuais.\n\n 📌 Ideal para gestores, coordenadores e professores\n 🌐 Curso 100% EAD — estude de onde estiver\n 🗓️ Início das aulas em agosto\n 🎁 Condições especiais para novas matrículas\n","time":"29/01/2026 15:29:52"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"29/01/2026 15:29:56"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"29/01/2026 15:30:25"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"29/01/2026 15:30:26"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"29/01/2026 15:31:08"},{"role":"client","text":"Gostaria de saber sobre o valor e quantas parcelas é o curso","time":"29/01/2026 15:31:36"},{"role":"client","text":"Gestão escolar","time":"29/01/2026 15:31:47"},{"role":"agent","text":"*Karina Pimentel:*  PÓS-GRADUAÇÃO EM GESTÃO ESCOLAR.\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n480 horas + 2 disciplinas optativas\n\nDISCIPLINAS\nDisciplinas: 12 + 2 disciplinas optativas\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"29/01/2026 15:32:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  O valor de investimento na Pós-graduação em Gestão Escolar será de: 16 mensalidades de R$ 479,16.\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"29/01/2026 15:32:55","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"29/01/2026 15:33:11","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Ok, Karina. Estou fazendo cotação agora. Qualquer coisa volto aqui novamente. Obrigado 🙏🏾","time":"29/01/2026 15:35:24"},{"role":"client","text":"Atendimento Finalizado!\n\nProfessor Assis Barroso, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"30/01/2026 15:51:59"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"30/01/2026 15:52:00"},{"role":"client","text":"Professor Assis Barroso, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"30/01/2026 16:07:00"}]$tag$, $tag$2026-01-29 15:26:58+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_concl